                    </div>
                </div>
            </Modal>

            {/* --- SMART EXPORT PROGRESS MODAL --- */}
            {exportState.isOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4 animate-in fade-in duration-300">
