                        {/* Close Button - Added per request */}
                        <button 
                            onClick={() => setExportState(prev => ({ ...prev, isOpen: false, isPaused: true }))}
                            className="absolute top-4 right-4 p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-all z-10"
