                                                !selectedFindings[result.clauseId] ? 'opacity-60 grayscale border-gray-300' : 
                                                result.status === 'COMPLIANT' ? 'border-emerald-500' : 
                                                result.status === 'NC_MAJOR' ? 'border-red-600' : 
                                                result.status === 'NC_MINOR' ? 'border-orange-500' : 
