                                </div>
                                {!exportState.isPaused && !exportState.isFinished && (
                                    <span className="text-xs font-mono bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 px-2 py-1 rounded animate-pulse">
