import React, { useState, useEffect } from 'react';
import { Icon, Modal } from './UI';
import { Clause } from '../types';
import { copyToClipboard } from '../utils';

interface ReferenceClauseModalProps {
    isOpen: boolean;
    onClose: () => void;
    clause: Clause | null;
    standardName?: string;
    fullText: string;
    isLoading: boolean;
    onInsert: (text: string) => void;
}

const ReferenceClauseModal = ({
    isOpen,
    onClose,
    clause,
    standardName,
    fullText,
    isLoading,
    onInsert
}: ReferenceClauseModalProps) => {
    const [isCopied, setIsCopied] = useState(false);

    if (!isOpen) return null;

    const handleCopy = () => {
        copyToClipboard(fullText);
        setIsCopied(true);
        setTimeout(() => setIsCopied(false), 2000);
    };

    const handleInsert = () => {
        onInsert(fullText);
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-3">
                    <Icon name="BookOpen" size={20} className="text-indigo-500" />
                    <span>Reference: {standardName}</span>
                </div>
            }
        >
            <div className="flex flex-col gap-4">
                <div className="p-3 bg-gray-50 dark:bg-slate-800 rounded-lg border border-gray-100 dark:border-slate-700">
                    <h4 className="text-sm font-bold text-slate-800 dark:text-slate-200">
                        [{clause?.code}] {clause?.title}
                    </h4>
                </div>

                <div className="relative h-64 max-h-[40vh] bg-gray-100 dark:bg-slate-950/50 rounded-lg p-4 border border-gray-200 dark:border-slate-800 overflow-y-auto custom-scrollbar">
                    {isLoading ? (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500">
                            <Icon name="Loader" size={24} className="animate-spin text-indigo-500 mb-4" />
                            <p className="font-bold">Contacting AI knowledge base...</p>
                            <p className="text-xs">Fetching verbatim clause text.</p>
                        </div>
                    ) : (
                        <pre className="text-sm text-slate-600 dark:text-slate-300 whitespace-pre-wrap font-sans leading-relaxed">
                            {fullText}
                        </pre>
                    )}
                </div>

                <div className="flex justify-end gap-3 mt-2">
                    <button
                        onClick={handleCopy}
                        disabled={isLoading || !fullText}
                        className={`h-10 px-4 ${isCopied ? 'bg-green-500' : 'bg-white dark:bg-slate-800'} border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 disabled:opacity-50`}
                    >
                        <Icon name={isCopied ? 'CheckThick' : 'Copy'} size={14} />
                        {isCopied ? 'Copied!' : 'Copy Full Text'}
                    </button>
                    <button
                        onClick={handleInsert}
                        disabled={isLoading || !fullText}
                        className={`h-10 px-4 ${isInserted ? 'bg-green-500' : 'bg-indigo-600 hover:bg-indigo-700'} text-white rounded-xl font-bold text-xs shadow-lg shadow-indigo-500/30 transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50`}
                    >
                        <Icon name="Plus" size={14} />
                        Insert into Evidence
                    </button>

