        setApiKeys(prev => prev.map(k => k.id === id ? { 
            ...k, 
            status: finalStatus,
            latency: latency,
            activeModel: finalStatus === 'valid' ? bestModel : k.activeModel,
            lastChecked: new Date().toISOString()
        } : k));
    };

