                                                    <span className="text-[9px] font-mono bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-300 px-1.5 rounded border border-blue-100 dark:border-blue-800/30">
                                                        {profile.activeModel.replace('gemini-', '')}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
