    const searchQuery = useDebounce(searchQueryRaw, 300);

    const startResizing = (e: React.MouseEvent) => {
        if ((e.target as Element).classList.contains('resize-handle')) {
            e.preventDefault();
            setIsResizing(true);
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none'; 
        }
    };

    useEffect(() => {
        const stopResizing = () => {
            if (isResizing) {
                setIsResizing(false);
                document.body.style.cursor = '';
                document.body.style.userSelect = '';

                if (sidebarRef.current) {
                    const finalWidth = parseInt(sidebarRef.current.style.width, 10);
                    if (!isNaN(finalWidth)) {
                        setWidth(finalWidth);
                    }
                }
            }
        };

        const resize = (e: MouseEvent) => {
            if (isResizing && sidebarRef.current) {
                const MIN_SIDEBAR_WIDTH = 390; 
                const MIN_MAIN_CONTENT_WIDTH = 375; 
                const MAX_SIDEBAR_LIMIT = 800;

                const maxSidebarWidth = Math.min(MAX_SIDEBAR_LIMIT, window.innerWidth - MIN_MAIN_CONTENT_WIDTH);
                const newWidth = Math.max(MIN_SIDEBAR_WIDTH, Math.min(e.clientX, maxSidebarWidth));

                sidebarRef.current.style.width = `${newWidth}px`;
            }
        };

        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', stopResizing);
        }
        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', stopResizing);
        };
    }, [isResizing, setWidth]);

    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        if (isResizing) return;
        const target = e.currentTarget;
        const scrollTop = target.scrollTop;
        const SCROLL_THRESHOLD = 50; 

        if (scrollTop > SCROLL_THRESHOLD && isHeaderVisible) setIsHeaderVisible(false);
        else if (scrollTop <= SCROLL_THRESHOLD && !isHeaderVisible) setIsHeaderVisible(true);
    };

    useEffect(() => {
        if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
    }, [standardKey]);

    const runHealthCheck = () => {
        if (!standardKey || !standards[standardKey]) return { isHealthy: false, score: 0, integrity: [], completeness: [] };
        const data = standards[standardKey];
        const integrity: { label: string, status: 'pass' | 'fail', detail: string }[] = [];
        const completeness: { label: string, status: 'pass' | 'fail', detail: string }[] = [];

        const flatten = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
            acc.push(c);
            if (c.subClauses) acc.push(...flatten(c.subClauses));
            return acc;
        }, [] as Clause[]);
        const flatList = flatten(data.groups.flatMap(g => g.clauses));

        const missingDesc = flatList.filter(c => !c.description || c.description.trim().length < 2).length;
        integrity.push({ label: 'Content Quality', status: missingDesc === 0 ? 'pass' : 'fail', detail: missingDesc === 0 ? 'Descriptions OK' : `${missingDesc} incomplete` });

        const uniqueCodes = new Set(flatList.map(c => c.code));
        const duplicateCount = flatList.length - uniqueCodes.size;
        integrity.push({ label: 'Data Cleanliness', status: duplicateCount === 0 ? 'pass' : 'fail', detail: duplicateCount === 0 ? 'Clean' : `${duplicateCount} Duplicates` });

        if (standardKey.includes("9001")) {
            ['8.4', '8.6', '8.7', '7.1.4'].forEach(code => {
                completeness.push({ label: `Clause ${code}`, status: flatList.some(c => c.code === code) ? 'pass' : 'fail', detail: flatList.some(c => c.code === code) ? 'Present' : 'Missing (Required)' });
            });
        }

        if (standardKey.includes("27001")) {
            const annexItems = flatList.filter(c => c.code.startsWith("A."));
            const isFullSet = annexItems.length >= 90; 
            completeness.push({ label: 'Annex A Controls', status: isFullSet ? 'pass' : 'fail', detail: isFullSet ? `${annexItems.length} Controls (OK)` : `${annexItems.length}/93 (Incomplete)` });
        }

        const integrityPass = integrity.every(i => i.status === 'pass');
        const completenessPass = completeness.every(i => i.status === 'pass');
        const isHealthy = integrityPass && completenessPass;
        const totalItems = integrity.length + completeness.length;
        const passItems = integrity.filter(i => i.status === 'pass').length + completeness.filter(i => i.status === 'pass').length;
        const score = Math.round((passItems / (totalItems || 1)) * 100);

        return { isHealthy, score, integrity, completeness };
    };

    const handleAutoRepair = async () => {
        if (!standardKey || !standards[standardKey]) return;
        setIsRepairing(true);
        setRepairStats(null);
        try {
            const currentStandard = JSON.parse(JSON.stringify(standards[standardKey])) as Standard; 
            const missingClauses: {ref: Clause, code: string, title: string}[] = [];
            let duplicateRemovedCount = 0;

            const findMissing = (list: Clause[]) => list.forEach(c => {
                if (!c.description || c.description.trim().length < 5) missingClauses.push({ ref: c, code: c.code, title: c.title });
                if (c.subClauses) findMissing(c.subClauses);
            });
            currentStandard.groups.forEach(g => findMissing(g.clauses));

            if (missingClauses.length > 0) {
                const targets = missingClauses.map(i => ({ code: i.code, title: i.title }));
                const jsonStr = await generateMissingDescriptions(targets);
                const descriptions = cleanAndParseJSON(jsonStr);
                const descMap = Array.isArray(descriptions) ? descriptions.reduce((acc, item) => (item.code && item.description && (acc[item.code] = item.description), acc), {}) : {};

                missingClauses.forEach(item => {
                    if (descMap[item.code]) {
                        item.ref.description = descMap[item.code];
                        repairedIds.push(item.ref.id);
                    }
                });
            }

            const cleanClauses = (clauses: Clause[]): Clause[] => {
                const seenCodes = new Set<string>();
                return clauses.filter(c => {
                    if (seenCodes.has(c.code)) {
                        duplicateRemovedCount++;
                        return false;
                    }
                    seenCodes.add(c.code);
                    if (c.subClauses) c.subClauses = cleanClauses(c.subClauses);
                    return true;
                });
            };
            currentStandard.groups.forEach(g => { g.clauses = cleanClauses(g.clauses); });

            onUpdateStandard(currentStandard);
            setRepairedIds(repairedIds);
            setRepairStats({ fixed: repairedIds.length, cleaned: duplicateRemovedCount });
        } catch (e) { console.error("Repair failed", e); alert("Failed to repair automatically.");
        } finally { setIsRepairing(false); }
    };

    const handleCopySelectedClauses = () => {
        if (!standardKey || !standards[standardKey]) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standards[standardKey].groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const handleSingleClauseInsert = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        onInsertClause(c);
        setInsertedClauseId(c.id);
        setTimeout(() => setInsertedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => [c.id, ...(c.subClauses ? c.subClauses.flatMap(getAllIds) : [])];
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => list.flatMap(c => [c.id, ...(c.subClauses ? getAllIds(c.subClauses) : [])]);
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !groupIds.includes(id)) : [...new Set([...prev, ...groupIds])]);
    };

    const allGroupIds = standards[standardKey]?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;
    const toggleExpandAll = () => areAllGroupsExpanded ? setExpandedGroups([]) : setExpandedGroups(allGroupIds);
    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const getChildSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getChildSelectionStatus);
            return { all: selectedClauses.includes(item.id) && subRes.every(r => r.all), some: selectedClauses.includes(item.id) || subRes.some(r => r.some) };
        };
        const selection = getChildSelectionStatus(c);
        const isCopied = copiedClauseId === c.id;
        const isInserted = insertedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-4 border-l-2 dark:border-slate-800' : ''}`}>
                <div className={`group flex items-start gap-3 p-2 rounded-xl transition-all duration-200 cursor-pointer ${isSelected ? 'bg-indigo-50/80 dark:bg-indigo-900/20 translate-x-1' : isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/50 dark:hover:bg-slate-800/50 hover:translate-x-1'}`}>
                    <button onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} className={`mt-1 flex-shrink-0 transition-colors duration-200 ${selection.some ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-gray-300 dark:text-slate-600 hover:text-gray-400'}`}>
                        {selection.all ? <Icon name="CheckSquare" size={16}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={16}/>}
                    </button>
                    <div className="flex-1 min-w-0" onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}>
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-1.5 flex-wrap">
                                <span className="text-xs font-bold text-indigo-700 dark:text-indigo-400 uppercase shrink-0 bg-indigo-50 dark:bg-indigo-900/30 px-1 rounded">{c.code}</span>
                                <span className="text-sm text-slate-900 dark:text-slate-100 font-medium tracking-tight leading-tight group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{c.title}</span>
                                {isRepaired && <span className="text-[9px] font-black bg-emerald-100 text-emerald-600 px-1.5 py-0.5 rounded-md animate-pulse">UPDATED</span>}
                            </div>
                            <div className="flex items-center gap-1">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1 transition-all transform duration-300 opacity-0 group-hover:opacity-100 text-gray-300 hover:text-cyan-500 dark:hover:text-cyan-400 hover:scale-110" title="Reference original text">
                                    <Icon name="BookOpen" size={14} />
                                </button>
                                <button onClick={(e) => handleSingleClauseInsert(e, c)} className={`p-1 transition-all transform duration-300 ${isInserted ? 'text-emerald-500 scale-125 opacity-100' : 'opacity-0 group-hover:opacity-100 text-gray-300 hover:text-emerald-500 dark:hover:text-emerald-400 hover:scale-110'}`} title={isInserted ? "Inserted!" : "Insert Summary into Evidence"}>
                                    <Icon name={isInserted ? "CheckThick" : "Quote"} size={isInserted ? 20 : 14} />
                                </button>
                                <button onClick={(e) => handleSingleClauseCopy(e, c)} className={`p-1 transition-all transform duration-300 ${isCopied ? 'text-emerald-500 scale-125 opacity-100' : 'opacity-0 group-hover:opacity-100 text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 hover:scale-110'}`} title={isCopied ? "Copied!" : "Copy Clause Reference"}>
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={isCopied ? 20 : 14} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={12} className={`text-gray-400 mt-0.5 shrink-0 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        <div className="text-xs text-slate-500 dark:text-slate-400 italic mt-1.5 leading-relaxed block w-full whitespace-normal border-t border-gray-100 dark:border-slate-800 pt-1">
                            {c.description}
                        </div>
                    </div>
                </div>
                <div className={`grid transition-all duration-300 ease-in-out ${hasSubs && isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">{hasSubs && <div className="mt-1 flex flex-col">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}</div>
                </div>
            </div>
        );
    };

    const renderClauses = () => {
        if (!standardKey || !standards[standardKey]) return <div className="text-center text-gray-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>;
        const data = standards[standardKey];

        const getGroupColorClass = (title: string) => {
            const t = title.toUpperCase();
            if (t.includes('PLAN')) return 'bg-blue-600 dark:bg-blue-500 shadow-blue-500/20';
            if (t.includes('SUPPORT')) return 'bg-purple-600 dark:bg-purple-500 shadow-purple-500/20';
            if (t.includes('DO')) return 'bg-orange-600 dark:bg-orange-500 shadow-orange-500/20';
            if (t.includes('CHECK') || t.includes('ACT')) return 'bg-emerald-600 dark:bg-emerald-500 shadow-emerald-500/20';
            if (t.includes('ANNEX')) return 'bg-rose-600 dark:bg-rose-500 shadow-rose-500/20';
            return 'bg-slate-800 dark:bg-slate-700';
        };

        return data.groups.map(g => {
            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
            const matchesSearch = (c: Clause): boolean => {
                const term = searchQuery.toLowerCase();
                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || c.description.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
            };
            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
            if (filteredClauses.length === 0) return null;

            return (
                <div key={g.id} className="mb-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300 hover:shadow-md">
                    <div className="flex items-center justify-between p-3.5 bg-gray-50/50 dark:bg-slate-800/30 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors" onClick={() => toggleGroupExpand(g.id)}>
                        <div className="flex items-center gap-3">
                            <button onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }} className={`p-2 rounded-xl shadow-lg text-white ${getGroupColorClass(g.title)} hover:scale-110 active:scale-95 transition-transform duration-300`} title="Click to Select/Deselect All in Group">
                                <Icon name={g.icon} size={14}/>
                            </button>
                            <h4 className="text-xs font-black text-slate-950 dark:text-white uppercase tracking-widest">{g.title}</h4>
                        </div>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                    </div>
                    <div className={`grid transition-all duration-300 ease-in-out ${isGroupExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden bg-white dark:bg-slate-900"><div className="p-2 space-y-1">{filteredClauses.map(c => renderClauseItem(c))}</div></div>
                    </div>
                </div>
            );
        });
    };

    const auditFieldIconColor = "text-indigo-700 dark:text-indigo-400";
    const health = runHealthCheck();
    // FIX: Corrected the variable name from STANDARDS to STANDARDS_DATA and completed the truncated line.
    const isCustomStandard = !STANDARDS_DATA[standardKey] || (standards[standardKey] && standards[standardKey] !== STANDARDS_DATA[standardKey]);

    return (
        <div ref={sidebarRef} className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl z-50 relative shrink-0 transition-[width] duration-300 ease-in-out`} style={{ width: isOpen ? width : 0 }}>
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 transition-colors z-50 group resize-handle" onMouseDown={startResizing} />}
            <div className={`flex-shrink-0 transition-all duration-300 ${isHeaderVisible ? 'p-5' : 'p-3'} border-b border-gray-100 dark:border-slate-800 min-w-[360px] bg-white dark:bg-slate-900`}>
                <div className="space-y-3">
                    <div className="relative">
                        <IconSelect icon="Book" iconColor={auditFieldIconColor} value={standardKey} onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} options={[...Object.keys(standards).map(k => ({ value: k, label: standards[k].name })), {value: "ADD_NEW", label: "+ Add New Standard..."}]} defaultText="Select ISO Standard" />
                        {standardKey && (
                            <button onClick={() => setShowIntegrityModal(true)} className={`absolute -top-2 -right-2 p-1.5 rounded-full shadow-2xl transition-all hover:scale-110 active:scale-95 text-white ring-4 ring-white dark:ring-slate-900 ${health.score === 100 ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Standard Integrity Status">
                                <Icon name={health.score === 100 ? "CheckCircle2" : "AlertCircle"} size={14}/>
                            </button>
                        )}
                    </div>
                    <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
                    <div className="grid grid-cols-2 gap-3">
                        <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                        <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="Audit ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                    </div>
                    <div className={`grid grid-cols-2 gap-3 transition-all duration-300 ease-in-out ${isInfoExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden col-span-2">
                             <div className="flex flex-col gap-3 pt-3">
                                 <IconInput icon="Users" iconColor={auditFieldIconColor} placeholder="Department" value={auditInfo.department} onChange={(e: any) => setAuditInfo({...auditInfo, department: e.target.value})} />
                                 <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Auditee/Interviewee" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                                 <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                             </div>
                        </div>
                    </div>
                </div>
                 <button onClick={() => setIsInfoExpanded(!isInfoExpanded)} className="w-full mt-2 text-xs text-slate-400 hover:text-indigo-500 flex items-center justify-center gap-1">
                    {isInfoExpanded ? 'Show Less' : 'Show More'} <Icon name="ChevronDown" size={12} className={`transition-transform ${isInfoExpanded ? 'rotate-180' : ''}`}/>
                </button>
            </div>
            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/40 dark:bg-slate-950/40 min-w-[360px]">
                <div className="p-3 border-b border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1">
                            <span className="absolute left-3 top-2.5 text-blue-700 dark:text-blue-400 font-bold"><Icon name="Search" size={14}/></span>
                            <input className="w-full pl-9 pr-3 py-2 text-xs bg-gray-100 dark:bg-slate-800 rounded-xl outline-none text-slate-800 dark:text-slate-200 placeholder-gray-400 border border-transparent focus:border-indigo-100" placeholder="Search clauses by code or content..." value={searchQueryRaw} onChange={e => setSearchQueryRaw(e.target.value)}/>
                        </div>
                        <button onClick={toggleExpandAll} className="p-2 rounded-xl bg-gray-100 dark:bg-slate-800 text-slate-500 hover:bg-indigo-50 dark:hover:bg-slate-700 hover:text-indigo-600 transition-colors" title={areAllGroupsExpanded ? "Collapse All" : "Expand All"}>
                           <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={16} />
                        </button>
                        {selectedClauses.length > 0 && (
                            <div className="flex gap-2">
                                <button onClick={handleCopySelectedClauses} className="p-2 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 hover:bg-indigo-100 transition-colors relative shadow-sm border border-indigo-100 dark:border-indigo-900/30" title="Copy Selected Clauses">
                                    <Icon name="Copy" size={16} />
                                </button>
                                <button onClick={() => setSelectedClauses([])} className="p-2 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 hover:bg-red-100 transition-colors relative shadow-sm border border-red-100 dark:border-red-900/30" title="Clear All">
                                    <Icon name="Trash2" size={16} />
                                    <div className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900 shadow-sm">{selectedClauses.length}</div>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
                <div ref={scrollContainerRef} onScroll={handleScroll} className="flex-1 overflow-y-auto custom-scrollbar p-3">{renderClauses()}</div>
            </div>

            <Modal isOpen={showIntegrityModal} title="Standard Health Index" onClose={() => setShowIntegrityModal(false)}>
                 <div className="space-y-6">
                    <div className="flex items-center gap-5 p-5 rounded-3xl bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700 shadow-inner">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-black shadow-xl ring-4 ring-white dark:ring-slate-700 ${health.score === 100 ? 'bg-gradient-to-br from-emerald-400 to-emerald-600' : 'bg-gradient-to-br from-orange-400 to-orange-600'}`}>
                            {health.score}%
                        </div>
                        <div className="flex-1">
                            <h4 className="font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight">Data Health</h4>
                            <p className="text-xs text-slate-500 dark:text-slate-400 leading-snug mt-1">{health.score === 100 ? 'Excellent! Data is complete and structured.' : 'Information might be incomplete for professional audit.'}</p>
                        </div>
                    </div>
                    <div className="space-y-3">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Integrity Checklist</h5>
