                                        {isReportLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                        <span className="hidden md:inline">{isReportLoading ? "Synthesizing Report..." : "Generate Final Report"}</span>
                                    </button>

