                        </p>
                    </div>
                </div>
            </Modal>

            {/* --- SMART EXPORT PROGRESS MODAL --- */}
            {exportState.isOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4 animate-in fade-in duration-300">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col relative">

